// ============================================================
// Check if it's Sunday and determine which timezones are at 6pm
// Runs every hour — only proceeds if it's Sunday AND a timezone
// group is hitting 6pm right now.
// ============================================================

const now = new Date();
const utcDay = now.getUTCDay(); // 0 = Sunday
const utcHour = now.getUTCHours();

// Only run on Sundays
if (utcDay !== 0) {
  return []; // Empty = stops workflow
}

// Map: UTC hour → which IANA timezones are at 6pm (18:00)
// We check both standard and daylight offsets
// This handles DST automatically by checking the actual local time
const timezoneGroups = [
  'America/New_York',
  'America/Chicago', 
  'America/Denver',
  'America/Los_Angeles',
  'America/Anchorage',
  'Pacific/Honolulu',
  'America/Phoenix'
];

// Find which timezones are currently at 6pm
const targetTimezones = [];
for (const tz of timezoneGroups) {
  try {
    const localTime = new Date(now.toLocaleString('en-US', { timeZone: tz }));
    if (localTime.getHours() === 18) {
      targetTimezones.push(tz);
    }
  } catch (e) {
    // Skip invalid timezone
  }
}

if (targetTimezones.length === 0) {
  return []; // No timezone is at 6pm right now
}

// Also build a list of common timezone aliases that map to the same offset
const timezoneAliases = {
  'America/New_York': ['America/New_York', 'US/Eastern', 'Eastern', 'EST', 'EDT', 'ET', 'America/Detroit', 'America/Indiana/Indianapolis'],
  'America/Chicago': ['America/Chicago', 'US/Central', 'Central', 'CST', 'CDT', 'CT', 'America/Indiana/Knox', 'America/Menominee'],
  'America/Denver': ['America/Denver', 'US/Mountain', 'Mountain', 'MST', 'MDT', 'MT', 'America/Boise'],
  'America/Los_Angeles': ['America/Los_Angeles', 'US/Pacific', 'Pacific', 'PST', 'PDT', 'PT'],
  'America/Anchorage': ['America/Anchorage', 'US/Alaska', 'Alaska', 'AKST', 'AKDT', 'AKT'],
  'Pacific/Honolulu': ['Pacific/Honolulu', 'US/Hawaii', 'Hawaii', 'HST', 'HT'],
  'America/Phoenix': ['America/Phoenix', 'US/Arizona', 'Arizona', 'MST']
};

// Build the full list of timezone strings to match against
let allMatchingTimezones = [];
for (const tz of targetTimezones) {
  if (timezoneAliases[tz]) {
    allMatchingTimezones = allMatchingTimezones.concat(timezoneAliases[tz]);
  } else {
    allMatchingTimezones.push(tz);
  }
}

return {
  targetTimezones,
  allMatchingTimezones,
  utcHour,
  runTime: now.toISOString()
};

// Filter clients whose timezone matches the current 6pm group
const clients = $input.first().json;
const checkData = $('Check Sunday 6pm').first().json;
const matchingTimezones = checkData.allMatchingTimezones || [];

if (!Array.isArray(clients) || clients.length === 0) {
  return [];
}

// Filter clients by timezone match (case-insensitive)
const filtered = clients.filter(c => {
  const clientTz = (c.timezone || 'America/Chicago').trim();
  return matchingTimezones.some(tz => 
    tz.toLowerCase() === clientTz.toLowerCase()
  );
});

if (filtered.length === 0) {
  return [];
}

// Return each client as a separate item for the loop
return filtered.map(c => ({ json: c }));

// ============================================================
// Calculate Weekly Lead Stats from Supabase call_log
// ============================================================

const callLogs = $input.first().json;
const client = $('Split Into Batches').first().json;

const logs = Array.isArray(callLogs) ? callLogs : [];

// Total calls
const totalCalls = logs.length;

// Leads (is_lead = true OR lead_score >= 6)
const leads = logs.filter(l => l.is_lead === true || (l.lead_score && l.lead_score >= 6));
const totalLeads = leads.length;

// Hot leads (lead_score >= 8)
const hotLeads = logs.filter(l => l.lead_score && l.lead_score >= 8);
const totalHotLeads = hotLeads.length;

// Warm leads (score 6-7)
const warmLeads = logs.filter(l => l.lead_score && l.lead_score >= 6 && l.lead_score < 8);
const totalWarmLeads = warmLeads.length;

// Non-leads / spam (is_lead = false AND score < 3, or no transcript)
const spam = logs.filter(l => !l.is_lead && l.lead_score !== null && l.lead_score < 3);
const totalSpam = spam.length;

// General inquiries (not a lead, score 3-5)
const generalInquiries = logs.filter(l => !l.is_lead && l.lead_score >= 3 && l.lead_score < 6);
const totalGeneral = generalInquiries.length;

// Average lead score
const avgScore = logs.length > 0
  ? (logs.reduce((sum, l) => sum + (l.lead_score || 0), 0) / logs.length).toFixed(1)
  : '0';

// Total call duration
const totalDuration = logs.reduce((sum, l) => sum + (l.duration_seconds || 0), 0);
const avgDuration = logs.length > 0 ? Math.round(totalDuration / logs.length) : 0;

// Service breakdown
const serviceBreakdown = {};
logs.forEach(l => {
  const svc = l.service_requested || 'Other';
  serviceBreakdown[svc] = (serviceBreakdown[svc] || 0) + 1;
});

// Urgency breakdown
const urgencyBreakdown = {};
logs.forEach(l => {
  const urg = l.urgency || 'Unknown';
  urgencyBreakdown[urg] = (urgencyBreakdown[urg] || 0) + 1;
});

// Week range
const weekEnd = new Date();
const weekStart = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
const formatDate = (d) => d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });

return {
  // Client info
  company_name: client.company_name || 'Client',
  agent_name: client.agent_name || 'AI Receptionist',
  lead_email: client.lead_email || '',
  agent_id: client.agent_id || '',

  // Stats
  totalCalls,
  totalLeads,
  totalHotLeads,
  totalWarmLeads,
  totalSpam,
  totalGeneral,
  avgScore,
  totalDuration,
  avgDuration,
  serviceBreakdown,
  urgencyBreakdown,

  // Date range
  weekStart: formatDate(weekStart),
  weekEnd: formatDate(weekEnd),

  // Top leads for highlight section
  topLeads: leads.slice(0, 5).map(l => ({
    name: l.caller_name || 'Unknown',
    phone: l.caller_phone || '',
    service: l.service_requested || '',
    score: l.lead_score || 0,
    urgency: l.urgency || ''
  }))
};
